N, M = input().split()
N, M = int(N), int(M)
matrix = []

for i in range(N):
    row_input = input().split()
    row = []
    for num in row_input:
        row.append(int(num))
    matrix.append(row)

result = [[0 for i in range(N)] for i in range(M)]

for i in range(M):
    for j in range(N):
        result[i][j] = matrix[j][i]

for row in result:
    for num in row:
        print(num, end=" ")
    print()
